#include<bits/stdc++.h>
using namespace std;
struct FHQ_Treap
{
    struct node
    {
        int l,r;
        int key,val;
        int siz;
    }a[1100010];
    int cnt,root;
    FHQ_Treap():cnt(0),root(0){}
    void pushup(int x)
    {
        a[x].siz=a[a[x].l].siz+a[a[x].r].siz+1;
    }
    int newnode(int v)
    {
        int x=++cnt;
        a[x].l=a[x].r=0;
        a[x].val=v;
        a[x].key=rand();
        a[x].siz=1;
        return x;
    }
    void split(int p,int v,int &x,int &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        if(a[p].val<=v)
        {
            x=p;
            split(a[p].r,v,a[p].r,y);
        }
        else
        {
            y=p;
            split(a[p].l,v,x,a[p].l);
        }
        pushup(p);
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(a[x].key<a[y].key)
        {
            a[x].r=merge(a[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            a[y].l=merge(x,a[y].l);
            pushup(y);
            return y;
        }
    }
    int kth(int x,int k)
    {
        if(k==a[a[x].l].siz+1)
        {
            return x;
        }
        if(k<=a[a[x].l].siz)
        {
            return kth(a[x].l,k);
        }
        else
        {
            return kth(a[x].r,k-a[a[x].l].siz-1);
        }
    }
    void insert(int v)
    {
        int x,y,z;
        split(root,v,x,y);
        z=newnode(v);
        root=merge(merge(x,z),y);
    }
    void del(int v)
    {
        int x,y,z;
        split(root,v,x,z);
        split(x,v-1,x,y);
        y=merge(a[y].l,a[y].r);
        root=merge(merge(x,y),z);
    }
    int getrnk(int v)
    {
        int x,y;
        split(root,v-1,x,y);
        int ans=a[x].siz;
        root=merge(x,y);
        return ans+1;
    }
    int getkth(int v)
    {
        return a[kth(root,v)].val;
    }
    int getpre(int v)
    {
        return getkth(getrnk(v)-1);
    }
    int getnxt(int v)
    {
        return getkth(getrnk(v+1));
    }
}t;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        t.insert(x);
    }
    int lstans=0;
    int ans=0;
    while(m--)
    {
        int op,x;
        scanf("%d%d",&op,&x);
        x^=lstans;
        if(op==1)
        {
            t.insert(x);
        }
        else if(op==2)
        {
            t.del(x);
        }
        else if(op==3)
        {
            ans^=lstans=t.getrnk(x);
        }
        else if(op==4)
        {
            ans^=lstans=t.getkth(x);
        }
        else if(op==5)
        {
            ans^=lstans=t.getpre(x);
        }
        else
        {
            ans^=lstans=t.getnxt(x);
        }
    }
    printf("%d",ans);
    return 0;
}
